def generate_test_sample(edge_list):
    # Build an undirected adjacency map from the (possibly weighted) edge list.
    neighbors = {}
    for e in edge_list:
        if len(e) < 2:
            continue
        u, v = e[0], e[1]
        neighbors.setdefault(u, set()).add(v)
        neighbors.setdefault(v, set()).add(u)

    nodes = list(neighbors.keys())
    if len(nodes) < 2:
        raise ValueError("Edge list must contain at least two nodes.")

    # Prefer a pair that has at least one common neighbor (excluding themselves).
    # If a node w has at least two neighbors other than w, pick any two of them.
    for w, nbrs in neighbors.items():
        others = [n for n in nbrs if n != w]
        if len(others) >= 2:
            a, b = others[0], others[1]
            return [a, b]

    # Otherwise, fall back to any edge endpoints (valid but may yield empty common neighbors).
    for e in edge_list:
        if len(e) >= 2:
            return [e[0], e[1]]

    # Final fallback: first two distinct nodes found.
    return nodes[:2]

