def generate_nodes(edge_list):
    """
    Generate a deterministic 'nodes' list for TSP testing from an edge list.
    - Uses nodes from the largest connected component (by size; tie -> earliest occurrence).
    - If many nodes, returns up to 8 nodes, evenly spaced by first-appearance order.
    """
    # Track first-appearance order and build an undirected adjacency
    order = []
    pos = {}
    adj = {}
    for e in edge_list:
        if not isinstance(e, (list, tuple)) or len(e) < 2:
            continue
        u, v = e[0], e[1]
        if u not in pos:
            pos[u] = len(order)
            order.append(u)
        if v not in pos:
            pos[v] = len(order)
            order.append(v)
        adj.setdefault(u, set()).add(v)
        adj.setdefault(v, set()).add(u)

    if not order:
        return []

    # Find connected components via DFS in first-appearance order
    visited = set()
    components = []
    for n in order:
        if n in visited:
            continue
        stack = [n]
        visited.add(n)
        comp = []
        while stack:
            x = stack.pop()
            comp.append(x)
            for y in adj.get(x, ()):
                if y not in visited:
                    visited.add(y)
                    stack.append(y)
        components.append(set(comp))

    # Choose the largest component; break ties by earliest first appearance
    best_comp = None
    best_key = None  # compare (size, -earliest_index)
    for comp in components:
        earliest = min(pos[n] for n in comp)
        key = (len(comp), -earliest)
        if best_key is None or key > best_key:
            best_key = key
            best_comp = comp

    comp_nodes_ordered = [n for n in order if n in best_comp]
    m = len(comp_nodes_ordered)
    if m <= 8:
        return comp_nodes_ordered

    # Pick 8 evenly spaced nodes across the component's ordered list
    k = 8
    selected = []
    for i in range(k):
        j = int(round(i * (m - 1) / (k - 1)))
        if not selected or comp_nodes_ordered[j] != selected[-1]:
            selected.append(comp_nodes_ordered[j])

    # Backfill in the unlikely event of duplicates due to rounding
    if len(selected) < k:
        seen = set(selected)
        for n in comp_nodes_ordered:
            if n not in seen:
                selected.append(n)
                seen.add(n)
                if len(selected) == k:
                    break

    return selected
